const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const members = await membersService.getAllMembers(projectId);
    res.json({ members });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const { userId, role } = req.body;
    if (!userId || typeof userId !== 'string' || !role || typeof role !== 'string') {
      return sendError(res, 400, 'INVALID_INPUT', 'Invalid input');
    }
    const newMember = await membersService.addMember(projectId, userId, role);
    if (!newMember) {
      return sendError(res, 409, 'MEMBER_ALREADY_EXISTS', 'Member already exists');
    }
    res.status(201).json({ member: newMember });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;
