const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const status = req.query.status;
    let tasks = await tasksService.getAllTasks(projectId);
    if (status === 'done') {
      tasks = tasks.filter(task => task.status === 'done');
    }
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const { description } = req.body;
    if (!description || typeof description !== 'string' || description.trim() === '') {
      return sendError(res, 400, 'INVALID_DESCRIPTION', 'Invalid task description');
    }
    const newTask = await tasksService.createTask(projectId, description);
    res.status(201).json({ task: newTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const taskId = req.params.taskId;
    const { status } = req.body;
    if (!status || (status !== 'todo' && status !== 'done')) {
      return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
    }
    const updatedTask = await tasksService.updateTaskStatus(projectId, taskId, status);
    if (!updatedTask) {
      return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    }
    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;
